mapper.insert:

    SELECT
    'RENT_' || LPAD(SEQ_RENT_LISTING.NEXTVAL,6,'0')
    FROM
    DUAL


INSERT INTO RENT_LISTING (
RENT_LSTG_NO
,HO_NO
,RENT_TTL
,RENT_TYPE_CD
,DPST_AMT
,MTHLY_RENT_AMT
,RENT_LSTG_CN
,RCRT_LSTG_STTS_CD
,DEAL_STTS_CD
,MVIN_PSBL_DT
) VALUES (
#{rentLstgNo}
,#{hoNo}
,#{rentTtl}
,#{rentTypeCd}
,#{dpstAmt}
,#{mthlyRentAmt}
,#{rentLstgCn}
,#{rcrtLstgSttsCd}
,#{dealSttsCd}
,#{mvinPsblDt}
)

mapper.update:
UPDATE RENT_LISTING
SET RENT_TTL          = #{rentTtl}
  , RENT_TYPE_CD      = #{rentTypeCd}
  , DPST_AMT          = #{dpstAmt}
  , MTHLY_RENT_AMT    = #{mthlyRentAmt}
  , RENT_LSTG_CN      = #{rentLstgCn}
  , RCRT_LSTG_STTS_CD = #{rcrtLstgSttsCd}
  , DEAL_STTS_CD      = #{dealSttsCd}
  , MVIN_PSBL_DT      = #{mvinPsblDt}

WHERE RENT_LSTG_NO = #{rentLstgNo}

mapper.select:
SELECT dong_nm
FROM APT_UNIT
WHERE apt_cmplex_no = #{aptCmplexNo}

ORDER BY TO_NUMBER(
                 REGEXP_REPLACE(dong_nm, '[^0-9]')
         )
